var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"쿨럭! 쿨럭!","JPN":"ケホッ！　ケホッ！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기껏 입고 온 새 옷이 다 망가졌군. 대체 무슨 일이지?","JPN":"せっかく新調した服が台無しだな。いったい何事だ？","ENG":"I really shouldn't have busted out my new suit for this trip. What's going on?","TWN":"新衣服全毀了，到底是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누군가 그림자 놈들에게 폐건물을 집어 던진 모양입니다.","JPN":"何者かがシャドウどもに廃ビルを投げつけたようです。","ENG":"Someone must have tossed an abandoned building at the Shadows.","TWN":"看來是有人把廢棄大樓扔向了暗影。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 이 정도의 염동력자는 구 관리국 시절에도 몇 없었는데 대체 누가......?","JPN":"しかし、このレベルの念動力者は旧管理局時代にも\\n数えるほどしかいなかったはず。いったい誰が……？","ENG":"But we only had a handful of telekinetics with this kind of power, even back in the Old Administration... Could it be?","TWN":"這種念動力，在舊管理局時期也沒幾個人有啊，到底是誰……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"어서 돌격해, 알렉스! 겨우 잡은 기회를 놓칠 셈이냐!","JPN":"早く突撃しろ、アレックス！　せっかく掴んだ勝機を逃す気か！","ENG":"Charge, Alex! Don't miss this chance!","TWN":"快突擊，雅蕾克絲！別錯過大好機會！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"대장, 바퀴벌레가 나타났어. 지금은 철수해야 돼.","JPN":"隊長ちゃん、ゴキブリが出没したわ。今は撤退すべきよ。","ENG":"Commander, the Roach is here. We need to fall back for now.","TWN":"隊長，蟑螂出現了，必須撤退才行。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"흥! 그렇다면 오히려 잘된 일 아니냐!","JPN":"フン！　それならむしろ好都合ではないか！","ENG":"Hmpf! It's even better then!","TWN":"哼！那不是正好嗎！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그 역겨운 녀석 눈앞에서 저 안에 있는 것들을 모조리 죽여 버린다고 생각해 봐라!","JPN":"あの不愉快極まりない奴の目の前で\\n中にいる連中を皆殺しにしてやるところを想像してみろ！","ENG":"We could kill all her friends right in her disgusting face!","TWN":"我要在那個該死的傢伙面前殺光那裡面的東西！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래...... 이번에야말로 증명할 수 있어! 내가 저 명줄만 질긴 바퀴벌레보다 낫다는 걸!","JPN":"ああ……今回こそ証明できる！　あのしぶといだけの\\nゴキブリよりも私の方が上だってことをな！","ENG":"Yes... I'll prove it once and for all this time! That I'm better than that Roach who's got nothing to show except her persistence!","TWN":"沒錯……這次我一定能證明！我比那隻只有生命力的蟑螂更優秀！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"이번엔 내 말 들어. 대장.","JPN":"今は私の言うことを聞いて。隊長ちゃん。","ENG":"Listen to me closely, Commander.","TWN":"這次還是聽我的吧，隊長。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"어차피 기갑 병기들은 곧 멈출 거야. 동결도 해제됐으니까 부대를 정비하고 오면 돼.","JPN":"どうせ機甲兵器たちはもうすぐ止まるわ。凍結も解除されたし、\\n部隊を整備して出直せばいいじゃない。","ENG":"The armored machines are going to stop soon anyway. And with the stasis gone, we can regroup and come back.","TWN":"反正那些機甲兵器很快就會停止。凍結也已經解除了，我們只需要整頓部隊後再來就可以了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"안 돼! 그러다 저것들이 다시 함선을 동결시켜 버리면 어쩔 거냐!","JPN":"駄目だ！　あいつらがまた艦船を凍結させたらどうするつもりだ！","ENG":"No! What if they put the ship back under stasis?","TWN":"不！萬一他們重新凍結艦船，那又該怎麼辦！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"한 번 풀어 버린 이상 다시 동결시키는 건 불가능해.","JPN":"一度解かれた以上、再凍結は不可能よ。","ENG":"Once it's lifted, it's impossible to put it back under stasis.","TWN":"一旦解除，就不能重新凍結了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"대장도 클리파에서 흘러 들어오는 힘이 느껴지잖아. 이 힘만 있으면 우린 더 강해질 수 있어.","JPN":"隊長ちゃんもクリファ次元から流れ込んでくる力を感じるでしょう？\\nこの力さえあれば、私たちはさらに強くなれるわ。","ENG":"You can sense the power flowing from Qlipha too, don't you? We can grow stronger as long as we've got that power.","TWN":"隊長應該也感受到了從逆卡巴拉流出的力量吧。只要有這股力量，我們就能變得更強。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"그냥 기다리기만 하면, 전대장이 그토록 바라던 것도 쉽게 이룰 수 있단 말이야.","JPN":"何もせずにただ待ってさえいれば、隊長ちゃんが\\nずっと願ってきたことも簡単に叶えることができるの。","ENG":"All we need is to wait. Then you can achieve what you've always wanted without breaking a sweat.","TWN":"我們只需要等待，就能輕易達成隊長的願望了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"내가 저 바퀴벌레보다 우월하다는 사실을 증명할 수 있다, 그 뜻인가?","JPN":"私があのゴキブリより優れていると証明できる、ということか？","ENG":"You mean I can finally prove that I'm superior to that Roach?","TWN":"妳的意思是，這樣我就可以證明我比那個蟑螂更強了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래. 내 말 들어서 손해 본 적 있어?","JPN":"ええ。私の言う通りにして損したことはないでしょう？","ENG":"Yes. Come on, you know it's never a bad idea to listen to me.","TWN":"沒錯，聽我的話絕對不會吃虧的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};